var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 네? 알파트릭스 재단에서 전학생이요?","JPN":"はい？　アルファトリックス財団から転入生？","ENG":"What? A transfer student from the Alphatrix Foundation?","TWN":"什麼？從阿爾法崔克斯財團來的轉學生嗎？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 그렇습니다. 감찰 한 번 없던 알파트릭스 측에서 갑자기 전학생을 보낸다는군요.","JPN":"そうです。これまで監察をしたこともなかったアルファトリックス側から、急に転入生を送ると連絡がありました。","ENG":"Yes. Alphatrix, who has never submitted to an inspection, is suddenly sending us a transfer.","TWN":"沒錯，阿爾法崔克斯沒事突然送個轉學生過來。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 우리 같은 일반 학교가 이렇게 번듯한 시설을 차려서 운영되고 있는 건 어디까지나 알파트릭스의 후원 덕분입니다.","JPN":"我々のような一般学校がここまで立派な施設を持って運営できているのは、アルファトリックスの支援があってこそです。","ENG":"As you know, thanks to Alphatrix, our school has been operating with the good facilities.","TWN":"不過像我們這種普通的學校，都是因為有阿爾法崔克斯的贊助，才可以有這些設施與建設。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCIPAL_NPC_ALPHA_NULL","text":{"KOREA":" 그러니 각별히 신경 좀 써줘요, 선생. 내 말 무슨 뜻인지 알겠죠?","JPN":"なので特別に気にかけてあげてください。私の言葉の意味、わかりますね？","ENG":"So be nice when the transfer student comes. Do you understand me?","TWN":"所以你要多關照一下，聽懂我的意思嗎，老師？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 자, 오늘은 새 전학생이 왔어.","JPN":"さ、今日は新しく転入生が来ました。","ENG":"We have a new student today.","TWN":"大家，這是今天來的轉學生。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 나와서 간단하게 자기 소개해볼까?","JPN":"前に来て、簡単に自己紹介してみようか。","ENG":"Would you please introduce yourself?","TWN":"你可以出來跟大家自我介紹嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 대침식전을 선도하는 알파트릭스 이노베이션에서 지정사수를 맡고 있는 김초원이야.","JPN":"対侵食戦を先導するアルファトリックス・イノベーションで選抜射手を担当している、スズキ・ナオです。","ENG":"Hi, I’m Kim Chowon, designated marksman of Alphatrix Innovation, the leading anti-Corruption team.","TWN":"我叫金初源，在阿爾法崔克斯改革帶領的侵蝕戰中負責射手的位置。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 김 씨라고 부르든, 초원이라고 부르든 상관없어.","JPN":"スズキでも、ナオでもどちらでも好きに呼んでください。","ENG":"You can either call me Kim or Chowon, I don’t really care.","TWN":"隨便大家要叫我小金，或叫我初源都可以。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 알파트릭스의 이미지 메이킹 목적으로 위장 입학한 것뿐이니까. 친해지려고 시도하지 않아도 돼.","JPN":"アルファトリックスのイメージアップのための偽装入学なので、別に仲良くなろうとする必要はありません。","ENG":"I’m only here to promote Alphatrix, so you don’t have to be nice to me.","TWN":"我是因為要替阿爾法崔克斯打造企業形象，才會假裝過來上學，可以不用跟我做朋友沒關係。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 브리핑은 이상, 질문은?","JPN":"自己紹介は以上です。質問はありますか？","ENG":"That's it for the briefing. Any questions?","TWN":"以上，有問題嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":" 쟤 뭐야? 총을 가지고 있어. 머리가 살짝 이상한 거 아냐?","JPN":"何？　あの子。　銃を持ってる。ちょっと頭おかしいんじゃない？","ENG":"She has a gun. Is she crazy?","TWN":"她是怎樣？來上學還帶槍？頭殼壞掉喔？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":" 등굣길에 외제차에서 내리던 그 애 맞지? 부잣집 딸인가?","JPN":"外車で登校してきた子だよね？　どっかの金持ちの娘なのかな？","ENG":"I saw her getting out of a super nice car in the morning. Is she rich?","TWN":"她就是從進口車下來的女生吧？她是有錢人家的女兒喔？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":" 단순한 부자가 아니야. 외제차로 배웅해주던 사람 못 봤어? 알파트릭스 회장 손녀였잖아!","JPN":"ただの金持ちじゃないよ。一緒に外車に乗っていた人は、アルファトリックスの会長の孫娘だったんだって！","ENG":"She’s not just rich. Didn’t you see who brought her here? It was the granddaughter of the Alphatrix CEO!","TWN":"她可不是一般的有錢人家，你沒看到送她來的人嗎？根本是阿爾法崔克斯會長的孫女吧！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 저기, 초원아? 왜 학교에 총을 들고 온 거니?","JPN":"えっと、ナオさん？　どうして学校に銃を持ってきたの？","ENG":"Um, Chowon? Why did you bring a gun here?","TWN":"初源？來學校為什麼要帶槍呢？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 안심하세요. 학교에선 이건 대인 진압용 고무탄이니까요, 선생님.","JPN":"安心してください、先生。これは、対人鎮圧用のゴム弾ですから。","ENG":"Don’t worry, teacher. This is only a rubber bullet gun.","TWN":"老師請放心，在學校我只會用鎮壓人類的橡皮子彈而已。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 급소만 안 맞으면 이승 하직은 하지 않아요. 하고 싶어질 만큼 아프겠지만요.","JPN":"急所さえ当たらなければ、あの世に行くことはありません。死にたくなるほど痛いとは思いますけどね。","ENG":"It won’t kill you unless you’re hit on your vital points. It must be deathly painful, though.","TWN":"只要沒有命中要害，是不會有性命危險的，頂多是痛到生不如死而已。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 그, 그래도 별 이유도 없으면서 학교에서 무기를 휴대하는 건 곤란해.","JPN":"で、でも特別な理由もなく学校で武器を携帯するのは困るわ。","ENG":"Still, you should not bring a weapon to school without any reason.","TWN":"可是…又沒什麼特殊原因需求，帶槍來學校還是不太好吧？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 이해했습니다. 명목이 있으면 괜찮다는 거군요.","JPN":"わかりました。理由があればいいのですね？","ENG":"Oh, so you’re saying that I need a reason to bring a weapon here?","TWN":"原來如此，是需要一個名義嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":" 이 학교에도 자경단이나 보안팀이 있다면 지원하고 싶은데요.","JPN":"この学校にも自警団やセキュリティチームがあるのなら、志願したいのですが。","ENG":"If that’s the case, I would like to volunteer for the school security team.","TWN":"那請問學校有自衛隊或是安全組嗎？我自願加入。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TEACHER_NPC_ALPHA_NULL","text":{"KOREA":" 보, 보안팀…? 그런 건 없지만 그나마 비슷한 거라면…….","JPN":"セ、セキュリティチーム……？　それはないけど、似たようなものなら……","ENG":"A security team...? We don’t have such a thing, but...","TWN":"安…安全組…？學校沒有安全組，硬要說的話……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TEACHER_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_NULL","text":{"KOREA":" 하아… 하아… 하아…","JPN":"はあ……はあ……はあ……","ENG":"*Pant*","TWN":"呼呼…呼呼…呼呼…"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};